#include "controller.h"

#include <stdio.h>

static void controller_set_safe_idle(controller_t *controller)
{
    if (controller == 0) {
        return;
    }
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static void controller_apply_control_policy(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    /* Start in safe idle until both sensors are valid */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        return;
    }

    /* Check for timeout condition - sensor stale for more than 1000ms */
    uint32_t now_ms = 0U;  /* The caller provides the timestamp in input.now_ms */

    /* Control policy based on level and temperature */
    int level = controller->last_level;
    int temp = controller->last_temperature_c;

    /* Safety: if level is below minimum heating threshold, heater must be off */
    bool heater_must_be_off = (level < CONTROLLER_MIN_HEATING_LEVEL);

    /* Control logic based on level ranges */
    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        /* Level too low - fill the tank */
        controller->inlet_open = true;
        controller->heater_on = false;  /* Heater off when filling */
        controller->state = CONTROLLER_STATE_FILLING;
    }
    else if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        /* Level too high - close inlet */
        controller->inlet_open = false;
        /* Heater decision based on temperature */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temp at high level - can heat */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        }
        else if ((temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) && (temp <= CONTROLLER_TEMP_HIGH_THRESHOLD)) {
            /* In the early-off band, check for rising temperature */
            bool temp_rising = false;
            if (controller->previous_temperature_c != 0 && controller->last_temperature_ms > 0U) {
                temp_rising = (temp > controller->previous_temperature_c);
            }

            if (temp_rising) {
                /* Temperature rising - turn heater off early */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            else {
                /* Not rising - hold previous safe heater state */
                controller->heater_on = true;  /* Keep it on if we were heating */
                controller->state = CONTROLLER_STATE_HEATING;
            }
        }
        else if (temp >= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Temp too high - turn heater off */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }
        else {
            /* 45 <= temp < 47 - hold previous safe heater state */
            /* Keep current heater state (HOLDING) */
            if (controller->heater_on == false && controller->state != CONTROLLER_STATE_HEATING) {
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }
    }
    else {
        /* Level in safe range [60, 75] - decide based on temperature */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temp at safe level - heat it up */
            controller->inlet_open = false;
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        }
        else if ((temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) && (temp <= CONTROLLER_TEMP_HIGH_THRESHOLD)) {
            /* In the early-off band, check for rising temperature */
            bool temp_rising = false;
            if (controller->previous_temperature_c != 0 && controller->last_temperature_ms > 0U) {
                temp_rising = (temp > controller->previous_temperature_c);
            }

            if (temp_rising) {
                /* Temperature rising - turn heater off early */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            else {
                /* Not rising - hold previous safe heater state */
                controller->heater_on = true;  /* Keep it on if we were heating */
                controller->state = CONTROLLER_STATE_HEATING;
            }
        }
        else if (temp >= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Temp too high - turn heater off */
            controller->inlet_open = false;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }
        else {
            /* 45 <= temp < 47 at safe level - hold previous safe heater state */
            if (controller->heater_on == false && controller->state != CONTROLLER_STATE_HEATING) {
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }
    }

    /* Enforce safety: heater must be off if level < 55 */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        controller->heater_on = false;
        /* If we were in heating state, transition to filling or holding */
        if (controller->state == CONTROLLER_STATE_HEATING) {
            controller->state = CONTROLLER_STATE_FILLING;
        }
    }

    /* Hard temperature ceiling check - should never exceed 51C */
    if (temp > 51) {
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_HOLDING;
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle timeout/error conditions first - reset to safe idle */
    switch (input.kind) {
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller_set_safe_idle(controller);
        output.timed_out = true;
        break;
    }

    /* Process valid sensor inputs */
    switch (input.kind) {
    case CONTROLLER_INPUT_NONE:
        /* No new input - apply control policy with current state */
        controller_apply_control_policy(controller);
        break;

    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        /* Apply control policy after updating temperature */
        controller_apply_control_policy(controller);
        break;

    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        /* Apply control policy after updating level */
        controller_apply_control_policy(controller);
        break;
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

